INSERT INTO final_exam_config (id, total_questions, passing_score, time_limit) VALUES (1, 100, 90, 30);
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (1, '営業の本質として最も適切な定義はどれか？', '["自社製品を多くの顧客に販売する活動","顧客の課題を発見し解決策を提案する活動","競合他社との価格競争に勝つための活動","売上目標を達成するための数字管理活動"]', 1, '営業は単なる販売ではなく、顧客の課題を理解し解決策を提案する問題解決活動です。', 'A: 基礎マインドセット - 研修1', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (2, 'SPIN話法の「示唆質問」の主な目的は何か？', '["顧客の基本情報を収集するための質問","問題を放置した影響に気づかせる質問","自社製品の優位性を伝えるための質問","顧客の購買意欲を直接確認する質問"]', 1, '示唆質問は問題を放置した場合の影響を考えさせ、顧客自身が課題の大きさに気づくことを促します。', 'A: 基礎マインドセット - 研修1', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (3, '顧客が「特に困っていない」と言った時の対応は？', '["次の機会を待って一旦引き下がる対応","質問で潜在的な課題を引き出す対応","他社事例を紹介して必要性を訴える対応","価格メリットを強調して興味を引く対応"]', 1, '顧客は自分の課題に気づいていないことがあります。質問を通じて潜在ニーズを顕在化させます。', 'A: 基礎マインドセット - 研修1', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (4, '信頼構築フェーズを最初に行う理由として正しいのは？', '["効率的に商談を進めるための時間短縮策","信頼がなければ本当の課題を話さないため","競合他社との差別化を図るためのテクニック","会社のルールとして決められているため"]', 1, '信頼関係がなければ顧客は本当の課題を話しません。信頼構築が全ての基盤になります。', 'A: 基礎マインドセット - 研修1', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (5, '「売れる営業」と「売れない営業」の決定的な違いは？', '["話術の巧みさと説得力の高さにある","顧客視点で考え行動できるかどうか","訪問回数と活動量の多さにある","商品知識の深さと専門性にある"]', 1, 'トップ営業は顧客視点で考え行動します。自分本位ではなく顧客本位の姿勢が成果を生みます。', 'A: 基礎マインドセット - 研修2', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (6, '初回商談での理想的なヒアリングと提案の比率は？', '["ヒアリング3割、提案7割が効率的である","ヒアリング7割、提案3割が効果的である","ヒアリング5割、提案5割がバランス良い","状況次第で比率を変えるのが正解である"]', 1, '初回商談ではヒアリング7割、提案3割が推奨されます。顧客理解が提案の質を決めます。', 'A: 基礎マインドセット - 研修2', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (7, '営業における「準備8割」の考え方で正しいのは？', '["準備に時間をかけすぎず即行動すべき","徹底した準備が商談の成否を決める","準備より経験から学ぶ方が重要である","準備は最低限にして数をこなすべき"]', 1, '営業成果の8割は準備で決まります。顧客研究、想定問答、資料準備を徹底することが重要です。', 'A: 基礎マインドセット - 研修3', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (8, '顧客の「検討します」という返答への最適な対応は？', '["わかりました、と引き下がり連絡を待つ","検討のポイントや懸念点を具体的に確認","期間限定の特別価格を提示して急かす","上司を同行させて再度訪問のアポを取る"]', 1, '「検討します」の裏には懸念や疑問があります。具体的に確認して次のステップにつなげます。', 'A: 基礎マインドセット - 研修4', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (9, '心理学の「返報性の原理」を営業で活用する方法は？', '["高額商品を提案してから値引きを行う","先に価値ある情報提供で信頼を構築","競合の悪い評判を伝えて不安を煽る","購入特典を多く付けて得した気にさせる"]', 1, '返報性の原理では、先に価値を提供すると相手も返したくなります。情報提供が信頼構築につながります。', 'A: 基礎マインドセット - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (10, '「アンカリング効果」の営業での正しい活用法は？', '["最初に低価格を提示してから値上げする","最初に高い選択肢を見せて基準を作る","競合の高い価格を引き合いに出して比較","過去の取引価格を基準に交渉を進める"]', 1, '最初に提示された情報が判断基準になります。プレミアムプランを先に見せることで選択を誘導できます。', 'A: 基礎マインドセット - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (11, '営業で「社会的証明」を活用する効果的な方法は？', '["有名企業の導入実績を積極的に紹介する","SNSのフォロワー数をアピールする","業界紙への掲載記事を見せて説明する","自社の売上ランキングを提示して説明"]', 0, '「他の人も使っている」という情報は購買を後押しします。同業他社の導入実績が効果的です。', 'A: 基礎マインドセット - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (12, '「損失回避バイアス」を営業で活用する方法は？', '["導入しないことで得られる利益を説明","導入しないことで生じる損失を説明","導入による直接的なコスト削減を説明","導入企業の成功事例を詳しく説明する"]', 1, '人は得ることより失うことを強く避けます。導入しない場合の機会損失を伝えることが効果的です。', 'A: 基礎マインドセット - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (13, '営業の「ゴールデンサークル理論」でまず伝えるべきは？', '["What：何を売っているかの商品説明","Why：なぜこの事業をしているかの理念","How：どのように価値を提供するかの方法","Who：誰がこのサービスを使うかの対象"]', 1, 'サイモン・シネックの理論では「Why」から始めることで共感を生み、強い動機付けができます。', 'A: 基礎マインドセット - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (14, '営業における「傾聴」の正しい姿勢はどれか？', '["相手の話を聞きながら次の質問を考える","相手の言葉を遮らず最後まで聴き切る","重要なポイントだけを選んでメモを取る","話が長い場合は要点をまとめて確認する"]', 1, '傾聴とは相手の話を遮らず、最後まで聴き切ることです。これにより信頼関係が構築されます。', 'A: 基礎マインドセット - 研修5', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (15, '顧客との長期的な関係構築で最も重要なことは？', '["定期的な訪問で接触頻度を高めること","購入後も継続的な価値提供を行うこと","競合情報を常に収集して報告すること","新製品が出るたびに提案を行うこと"]', 1, '売って終わりではなく、継続的な価値提供が長期的な信頼関係と追加受注につながります。', 'A: 基礎マインドセット - 研修6', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (16, '「認知的不協和」を営業で活用するタイミングは？', '["初回訪問時に競合との違いを説明する時","購入直後に選択の正しさを確認する時","商談中に価格交渉を行う時に活用する","提案書を作成する際の構成を考える時"]', 1, '購入後は「本当に正しい選択だったか」と不安になります。その時に選択を肯定する情報を提供します。', 'A: 基礎マインドセット - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (17, '営業マインドセットの土台となる考え方で正しいのは？', '["数字を追いかければ結果は自然とついてくる","顧客の成功を自分の成功と捉えて行動する","効率を重視して短時間で多く回ることが重要","トーク力を磨けば誰でもトップ営業になれる"]', 1, '顧客の成功を自分の成功と捉える姿勢が、持続的な営業成果と信頼関係構築の土台になります。', 'A: 基礎マインドセット - 研修7', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (18, 'Symphonyシリーズが提供する3つの価値はどれか？', '["安い・早い・簡単の3つの価値を提供する","分かりやすい・つながる・売上が伸びる","自動化・効率化・最適化の3つの価値","集客・販売・管理の3つの価値を提供する"]', 1, 'Symphonyは「分かりやすい」「つながる」「売上が伸びる」の3つの価値で中古車販売を支援します。', 'B: Symphonyシリーズ - 研修11', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (19, 'Symphony販売管理の最大の特徴は何か？', '["業界最安値の月額料金で利用できること","一度の入力で複数メディアに一括掲載","AIによる自動価格設定機能があること","24時間365日の電話サポートがあること"]', 1, 'Symphony販売管理は一度の入力で10以上の広告メディアに一括掲載でき、二重入力を解消します。', 'B: Symphonyシリーズ - 研修12', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (20, 'Symphony整備請求と販売管理を連携するメリットは？', '["請求書の印刷コストを削減できること","顧客情報を共有しLTVを最大化できる","整備士の作業効率が向上すること","部品の在庫管理が自動化されること"]', 1, '販売と整備のデータ連携により、顧客との長期関係を構築しLTV（顧客生涯価値）を最大化できます。', 'B: Symphonyシリーズ - 研修13', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (21, 'シンフォニーワンプラの主な手数料体系はどれか？', '["月額固定費と成約手数料の二段階制","出品成約料と落札料の成約時のみ発生","年間契約で一括払いすると割引適用","在庫台数に応じた従量課金制を採用"]', 1, 'シンフォニーワンプラは固定費なしで、出品成約料と落札料の成約時のみ手数料が発生します。', 'B: Symphonyシリーズ - 研修14', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (22, 'ワンプラが競合サービスより優れている点は？', '["掲載台数が業界で最も多いこと","業界最安水準の手数料とSymphony連携","審査なしで誰でも利用開始できること","全国どこでも即日配送に対応すること"]', 1, 'ワンプラは業界最安水準の手数料と、Symphony販売管理との自動連携が競合との差別化ポイントです。', 'B: Symphonyシリーズ - 研修15', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (23, '製品間連携によるクロスセル提案のタイミングは？', '["初回商談時に全製品をセットで提案する","顧客の成長や課題発生時に段階的に提案","契約更新時にまとめて追加製品を提案","競合からの乗り換え時に全製品を提案"]', 1, '顧客の成長段階や新たな課題が発生したタイミングで、段階的にクロスセル提案を行います。', 'B: Symphonyシリーズ - 研修16', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (24, '小規模店舗（10台以下）への提案で響くポイントは？', '["大企業も使っている信頼性の高さを訴求","事務作業削減で接客時間を増やせること","多店舗展開時のスケーラビリティを説明","高度なデータ分析機能の活用方法を説明"]', 1, '小規模店舗は「時間がない」が最大の課題。事務作業削減による接客時間増加が響きます。', 'B: Symphonyシリーズ - 研修17', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (25, '中規模店舗（30-50台）が抱える典型的な課題は？', '["初期投資コストが大きすぎること","スタッフ間の情報共有と在庫回転率","広告メディアの選定に迷うこと","オーナーの営業力に依存していること"]', 1, '中規模店舗は組織化が進む中で、スタッフ間の情報共有や在庫回転率向上が課題になります。', 'B: Symphonyシリーズ - 研修18', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (26, '大規模・多店舗への導入アプローチで正しいのは？', '["全店舗に一斉導入して早期に効果を出す","1店舗でパイロット導入後に順次展開","本部のみに導入して各店舗は後から対応","繁忙期を避けて閑散期に一気に導入する"]', 1, '大規模導入は1店舗でパイロット導入し、成功事例を作ってから順次展開するのが確実です。', 'B: Symphonyシリーズ - 研修19', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (27, 'Symphony導入のROI計算で考慮すべき効果は？', '["直接的なコスト削減のみを計算する","時間削減・売上増加・コスト削減の3軸","競合との価格差のみを比較して計算","導入後1ヶ月の効果のみで判断する"]', 1, 'ROIは時間削減効果、売上増加効果、コスト削減効果の3軸で総合的に計算します。', 'B: Symphonyシリーズ - 研修20', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (28, '顧客から「高くないですか？」と言われた時の対応は？', '["すぐに値引きを提示して契約を急ぐ","ROI試算を見せて投資対効果を説明","他社はもっと高いと競合比較を行う","機能を減らした安いプランを提案する"]', 1, '価格の妥当性はROI試算で説明します。投資対効果を数字で示すことで納得を得られます。', 'B: Symphonyシリーズ - 研修21', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (29, '効果的なデモンストレーションの構成として正しいのは？', '["全機能を網羅的に30分かけて説明する","顧客の課題に絞りビフォーアフターを見せる","操作スピードを上げて多くの機能を紹介","カタログを見せながら口頭で説明する"]', 1, 'デモの目的は「価値を体験してもらうこと」。顧客の課題解決にフォーカスしたデモが効果的です。', 'B: Symphonyシリーズ - 研修22', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (30, 'Symphony導入で実現できる入力作業の削減率は？', '["約20%の入力作業を削減できる","約50%の入力作業を削減できる","約80%の入力作業を削減できる","入力作業を完全に自動化できる"]', 1, '一元管理による二重入力解消で、入力作業を約50%削減できます（実績ベース）。', 'B: Symphonyシリーズ - 研修12', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (31, '整備ビジネスが中古車販売店にとって重要な理由は？', '["車両販売より利益率が高いから","車検は定期的に発生する安定収益源だから","整備士の雇用を維持するために必要だから","法律で整備部門の設置が義務付けられている"]', 1, '車検は2年に1回必ず発生する継続収益です。価格競争の激しい車販を補完する安定収益源になります。', 'B: Symphonyシリーズ - 研修13', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (32, 'ワンプラで「仕入れ」と「業販出品」両方ができる利点は？', '["手数料が両方とも無料になること","仕入れルート拡大と在庫処分が同時に可能","オークション会員でなくても利用できる","全国どこでも送料無料で取引できる"]', 1, 'ワンプラは仕入れルートの拡大と売れない在庫の業販出品の両方ができ、在庫リスクを軽減します。', 'B: Symphonyシリーズ - 研修14', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (33, 'Symphonyの「100万件超のデータ」の活用方法は？', '["過去の販売履歴を検索できる","適正価格の判断に活用できる","顧客の個人情報を管理できる","競合店舗の情報を分析できる"]', 1, '100万件超のリアルタイム車両データにより、相場に基づいた適正価格の判断ができます。', 'B: Symphonyシリーズ - 研修11', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (34, 'Symphony導入提案で「使いこなせるか不安」への回答は？', '["マニュアルを熟読すれば大丈夫です","直感的UIと研修・専任サポートがあります","使えない機能は使わなくても大丈夫です","最初は私が代わりに操作します"]', 1, 'ITが苦手な方でも安心できるよう、直感的なUI、導入時研修、専任サポートがあることを伝えます。', 'B: Symphonyシリーズ - 研修21', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (35, '営業プロセスの最初のステップとして正しいのは？', '["商品知識を完璧に習得すること","見込み客の発掘とリスト作成","提案資料のテンプレートを作成","競合他社の情報を収集すること"]', 1, '営業プロセスはまず見込み客の発掘から始まります。ターゲット選定がその後の効率を決めます。', 'C: 営業プロセス - 研修23', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (36, 'テレアポで最初の15秒で伝えるべきことは？', '["自社製品の特徴と価格情報","自己紹介と電話した理由・目的","競合との比較における優位性","成功事例と導入効果の数字"]', 1, '最初の15秒で「誰が」「なぜ電話したか」を明確にし、相手の関心を引くことが重要です。', 'C: 営業プロセス - 研修24', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (37, '初回訪問の目的として最も重要なのは何か？', '["製品のデモンストレーションを行う","顧客の課題とニーズを深く理解する","見積書を提示して価格交渉を行う","契約書の内容を詳しく説明する"]', 1, '初回訪問の主目的は課題とニーズの理解です。提案は十分な理解の後に行います。', 'C: 営業プロセス - 研修25', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (38, '提案書作成で最も重視すべき点は何か？', '["デザインの美しさとページ数の多さ","顧客の課題と解決策の明確な対応関係","自社製品の全機能を網羅的に記載","競合他社との詳細な比較表の掲載"]', 1, '提案書は顧客の課題に対する解決策を明確に示すものです。課題と解決策の対応が最重要です。', 'C: 営業プロセス - 研修26', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (39, 'クロージングの最適なタイミングを見極める方法は？', '["商談開始から30分経過した時点","顧客の購買シグナルを見逃さない","全ての質問に回答し終えた時点","見積書を提出してから3日後"]', 1, 'クロージングは顧客の購買シグナル（質問の変化、前のめりの姿勢など）を察知して行います。', 'C: 営業プロセス - 研修27', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (40, '営業パイプライン管理で重要な指標はどれか？', '["訪問回数と移動距離の効率","各ステージの案件数と進捗率","提案書の作成にかかった時間","顧客との通話時間の長さ"]', 1, 'パイプライン管理では各ステージの案件数と進捗率を可視化し、ボトルネックを特定します。', 'C: 営業プロセス - 研修28', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (41, '商談で「予算がない」と言われた時の対応は？', '["予算ができたら連絡くださいと引く","本当の懸念点を確認する質問をする","すぐに大幅な値引きを提示する","分割払いプランを即座に提案する"]', 1, '「予算がない」は本当の理由ではないことが多いです。質問で真の懸念点を確認します。', 'C: 営業プロセス - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (42, 'BANTフレームワークの4要素として正しいのは？', '["Business, Analysis, Need, Time","Budget, Authority, Need, Timeline","Benefit, Action, Negotiation, Trust","Base, Approach, Network, Target"]', 1, 'BANTは予算(Budget)、決裁権(Authority)、ニーズ(Need)、導入時期(Timeline)の4要素です。', 'C: 営業プロセス - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (43, 'MEDDICフレームワークで「Economic Buyer」とは？', '["製品を実際に使用するエンドユーザー","最終的な購買決定権を持つ人物","予算管理を担当する経理担当者","技術的な評価を行う担当者"]', 1, 'Economic Buyerは最終的な購買決定権を持つ人物です。この人物へのアプローチが成約の鍵です。', 'C: 営業プロセス - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (44, '商談の「チャンピオン」を作る意義として正しいのは？', '["競合情報を内部から入手できるから","社内で自社の代わりに推進してくれるから","意思決定を早めてもらえるから","値引き交渉を有利に進められるから"]', 1, 'チャンピオンは顧客社内で自社製品を推進してくれる味方です。不在時の社内調整も担います。', 'C: 営業プロセス - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (45, '「ペインポイント」の特定で効果的な質問は？', '["御社の売上はいくらですか？","現状で最も困っていることは何ですか？","競合他社はどこを使っていますか？","いつまでに導入したいですか？"]', 1, 'ペインポイントは顧客の「痛み」です。直接的に困っていることを聞くことで特定できます。', 'C: 営業プロセス - 研修25', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (46, '商談で複数の意思決定者がいる場合の対応は？', '["一人のキーマンに絞ってアプローチ","全員のニーズと懸念を個別に把握する","最も役職が高い人だけに説明する","会議形式でまとめて説明する"]', 1, '複数の意思決定者がいる場合、それぞれの立場でのニーズと懸念を個別に把握することが重要です。', 'C: 営業プロセス - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (47, 'テストクロージングの正しい使い方は？', '["契約書を見せて反応を確認する方法","仮定の質問で購買意欲を確認する方法","期間限定特典で決断を迫る方法","上司の承認が必要と伝える方法"]', 1, 'テストクロージングは「もし〜だとしたら」と仮定の質問で顧客の購買意欲を確認する技法です。', 'C: 営業プロセス - 研修27', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (48, '失注案件の分析で最も重要なことは？', '["競合との価格差を詳細に分析する","失注理由を正確に把握し次に活かす","担当者を変えて再アプローチする","失注した顧客リストを作成する"]', 1, '失注理由を正確に把握し、次の商談に活かすことが継続的な改善につながります。', 'C: 営業プロセス - 研修28', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (49, 'リードナーチャリングの目的として正しいのは？', '["すぐに商談化できる見込み客を選別","時間をかけて購買意欲を高める活動","不要なリードをリストから削除する","リードの個人情報を詳しく収集する"]', 1, 'リードナーチャリングは、まだ購買準備ができていない見込み客を育成し、購買意欲を高める活動です。', 'C: 営業プロセス - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (50, '商談のゴール設定で正しいのはどれか？', '["とにかく契約を取ることをゴールにする","次のステップに進む合意を得ること","自社製品の全てを説明し終えること","顧客の全ての質問に回答すること"]', 1, '各商談のゴールは「次のステップに進む合意」です。一気に契約を目指すのではなく段階的に進めます。', 'C: 営業プロセス - 研修26', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (51, 'アポイント取得率を上げるための工夫は？', '["電話の回数を増やして確率で勝負","顧客にとってのメリットを明確に伝える","できるだけ早い日程を提案する","上司の名前を出して権威を示す"]', 1, 'アポ取得率向上には、顧客にとってのメリット（会う価値）を明確に伝えることが効果的です。', 'C: 営業プロセス - 研修24', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (52, '商談の冒頭で最初に行うべきことは？', '["自社製品のカタログを配布すること","アイスブレイクで場を和ませること","本日の議題と目的を確認すること","名刺交換を丁寧に行うこと"]', 1, '商談冒頭ではアイスブレイクで場を和ませ、信頼関係構築の土台を作ります。', 'D: 商談テクニック - 研修32', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (53, 'オープンクエスチョンの特徴として正しいのは？', '["「はい」「いいえ」で答えられる質問","自由に回答でき情報を深掘りできる質問","選択肢を提示して選んでもらう質問","数値で回答してもらう定量的な質問"]', 1, 'オープンクエスチョンは「なぜ」「どのように」など自由回答を促し、深い情報を引き出せます。', 'D: 商談テクニック - 研修33', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (54, '顧客の反論に対する最初の対応として適切なのは？', '["すぐに論理的な反論で説得を試みる","まず反論の背景にある懸念を理解する","他社事例を見せて安心させる","上司に相談すると伝えて持ち帰る"]', 1, '反論には必ず背景があります。まず懸念を理解してから、適切な対応を考えます。', 'D: 商談テクニック - 研修34', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (55, '価格交渉で値引きを求められた時の対応は？', '["即座に可能な範囲で値引きを提示","値引きの前に価値を再確認する","「これ以上は無理です」と断る","上司に確認しますと一旦持ち帰る"]', 1, '値引き要求には、まず提供価値を再確認します。価値が認められれば価格への不満は減少します。', 'D: 商談テクニック - 研修35', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (56, 'プレゼンテーションで最も重要なことは？', '["スライドのデザインを美しくすること","聴衆のニーズに合わせた内容にすること","全ての機能を漏れなく説明すること","時間通りに終わらせること"]', 1, 'プレゼンは聴衆のニーズに合わせることが最重要。相手が聞きたいことを中心に構成します。', 'D: 商談テクニック - 研修36', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (57, '商談中に顧客が腕を組んだ時の対応は？', '["話を続けてより詳しく説明する","オープンな質問で対話に戻す","資料を渡して読んでもらう","一旦休憩を提案する"]', 1, '腕組みは防御的な姿勢の表れです。オープンな質問で相手に発言機会を与え、対話に戻します。', 'D: 商談テクニック - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (58, '「ミラーリング」を商談で使う効果は？', '["自分の主張を相手に映し出す効果","相手との親近感と信頼を高める効果","相手の弱点を見つけ出す効果","商談時間を短縮する効果"]', 1, 'ミラーリングは相手の姿勢や話し方を鏡のように合わせることで、親近感と信頼を高めます。', 'D: 商談テクニック - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (59, 'クロージングで「沈黙」が効果的な理由は？', '["相手が考える時間を与えられるから","威圧感を与えて決断を促すから","自分の緊張を隠せるから","次の質問を考える時間ができるから"]', 0, 'クロージング後の沈黙は、相手に考える時間を与えます。焦って話し続けないことが重要です。', 'D: 商談テクニック - 研修37', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (60, '「二者択一法」のクロージングとはどのような方法か？', '["契約するかしないかを直接確認する方法","AとBどちらがいいかを選んでもらう方法","二人の上司に同時に提案する方法","二回に分けて契約を進める方法"]', 1, '二者択一法は「AプランとBプラン、どちらがご希望ですか？」と選択肢を示す技法です。', 'D: 商談テクニック - 研修37', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (61, '顧客が「競合と比較検討中」と言った時の対応は？', '["競合の悪い点を指摘して牽制する","比較検討のポイントを確認して差別化","値引きを提示して早期決定を促す","検討結果を待つと伝えて引き下がる"]', 1, '比較検討のポイントを確認し、そのポイントでの自社の強みを明確に伝えることが重要です。', 'D: 商談テクニック - 研修34', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (62, '商談で「ストーリーテリング」が効果的な理由は？', '["話が長くなり商談時間を稼げるから","論理より感情に訴え記憶に残りやすい","自分の話術をアピールできるから","顧客の質問を減らせるから"]', 1, 'ストーリーは論理的説明より感情に訴え、記憶に残りやすいため、説得力が増します。', 'D: 商談テクニック - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (63, '「FABE法」のプレゼン構成で正しい順序は？', '["Feature → Advantage → Benefit → Evidence","Fact → Analysis → Benefit → Example","Focus → Action → Benefit → End","Feature → Action → Base → Evidence"]', 0, 'FABEは特徴→利点→便益→証拠の順で説明し、顧客にとっての価値を明確にする技法です。', 'D: 商談テクニック - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (64, '商談での「ペーシング」の正しい使い方は？', '["早口で話して多くの情報を伝える方法","相手の話すスピードに合わせる方法","一定のペースで話し続ける方法","間を取らずにテンポよく話す方法"]', 1, 'ペーシングは相手の話すスピードやテンポに合わせることで、親近感と信頼を構築します。', 'D: 商談テクニック - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (65, '顧客の「今は忙しい」への効果的な対応は？', '["わかりました、と引き下がり後日連絡","忙しい理由を確認し短時間の価値を提案","上司からお電話させますと伝える","メールで資料を送りますと提案"]', 1, '「忙しい」の裏にある理由を確認し、短時間でも価値があることを伝えて時間を確保します。', 'D: 商談テクニック - 研修34', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (66, '商談のクロージングで避けるべきことは？', '["顧客に考える時間を与えること","顧客の決断を急かすこと","導入後のイメージを伝えること","不明点がないか確認すること"]', 1, '決断を急かすと顧客は防御的になります。余裕を持たせた方が成約率は上がります。', 'D: 商談テクニック - 研修37', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (67, '「推定承諾法」のクロージングの特徴は？', '["購入を前提とした質問で話を進める方法","購入を強く推薦する方法","購入しないとどうなるかを伝える方法","上司が承諾したと伝える方法"]', 0, '推定承諾法は「導入後の運用体制はどうされますか？」など購入前提の質問で自然に進めます。', 'D: 商談テクニック - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (68, '商談中のメモの取り方で正しいのは？', '["全ての発言を漏らさず記録する","キーワードと重要ポイントを記録する","メモは取らず会話に集中する","録音して後から文字起こしする"]', 1, '全て記録すると会話に集中できません。キーワードと重要ポイントに絞ってメモを取ります。', 'D: 商談テクニック - 研修33', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (69, 'CRM（顧客管理システム）を導入する最大の目的は？', '["営業の行動を監視すること","顧客との関係を一元管理し深めること","報告書作成の手間を削減すること","営業成績をランキング化すること"]', 1, 'CRMの目的は顧客情報を一元管理し、組織として顧客との関係を深めることです。', 'E: 顧客管理 - 研修41', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (70, '顧客のLTV（顧客生涯価値）を高める方法は？', '["初回購入時に高額商品を販売する","継続的な価値提供で長期関係を構築","紹介キャンペーンで新規顧客を増やす","値引きを行い購入頻度を上げる"]', 1, 'LTVは継続的な価値提供と長期関係構築によって高まります。売って終わりでは上がりません。', 'E: 顧客管理 - 研修42', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (71, '既存顧客へのフォローで最も重要なタイミングは？', '["契約更新の1ヶ月前のタイミング","導入直後の不安が大きい時期","競合からのアプローチがあった時","自社の新製品がリリースされた時"]', 1, '導入直後は不安が大きく、丁寧なフォローが信頼構築と継続利用につながります。', 'E: 顧客管理 - 研修43', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (72, '顧客からのクレーム対応で最初に行うべきことは？', '["事実確認をして原因を特定する","まず謝罪し顧客の話を傾聴する","解決策を即座に提示する","上司に報告して指示を仰ぐ"]', 1, 'クレーム対応はまず謝罪と傾聴から。感情を受け止めてから原因特定と解決に進みます。', 'E: 顧客管理 - 研修44', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (73, '顧客の「解約したい」への効果的な対応は？', '["解約手続きを迅速に進める対応","解約理由を確認し改善提案を行う対応","違約金について説明する対応","上司に代わってもらう対応"]', 1, '解約希望には理由を確認し、改善提案で引き留めを試みます。理由によっては解約阻止できます。', 'E: 顧客管理 - 研修44', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (74, '顧客セグメンテーションの目的として正しいのは？', '["優良顧客だけに営業リソースを集中","顧客特性に応じた最適なアプローチ","取引額の小さい顧客を切り捨てる","顧客リストを整理して管理を簡素化"]', 1, 'セグメンテーションは顧客を特性ごとに分け、それぞれに最適なアプローチを行うためです。', 'E: 顧客管理 - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (75, 'NPS（ネットプロモータースコア）の計算方法は？', '["満足度の平均点を100点満点で算出","推奨者の割合から批判者の割合を引く","リピート率と紹介率を掛け合わせる","クレーム数を顧客数で割って算出"]', 1, 'NPSは「他者に推奨したいか」を11段階で聞き、推奨者(9-10)％から批判者(0-6)％を引きます。', 'E: 顧客管理 - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (76, '顧客の「担当者が変わった」への対応で正しいのは？', '["新担当者に自社製品を一から説明","まず新担当者のニーズと状況を確認","前担当者との関係を新担当者に伝える","上司同士の挨拶の場を設定する"]', 1, '担当者変更時は、まず新担当者のニーズと状況を確認し、関係構築をやり直します。', 'E: 顧客管理 - 研修45', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (77, 'アップセルとクロスセルの違いで正しいのは？', '["アップセルは新規、クロスセルは既存向け","アップセルは上位版、クロスセルは関連商品","アップセルは法人、クロスセルは個人向け","アップセルは長期、クロスセルは短期契約"]', 1, 'アップセルは上位グレードへの誘導、クロスセルは関連する別商品の提案です。', 'E: 顧客管理 - 研修46', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (78, '顧客満足度調査の結果を活かす正しい方法は？', '["満足度が高い顧客にだけ追加提案","不満の声を分析し改善アクションにつなげる","調査結果を社内報告して共有する","次回調査時の比較データとして保管"]', 1, '満足度調査は不満の声を分析し、具体的な改善アクションにつなげることで価値を発揮します。', 'E: 顧客管理 - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (79, '「休眠顧客」の掘り起こしで効果的な方法は？', '["営業電話を頻繁にかけてアプローチ","過去の取引履歴を分析し価値ある情報提供","大幅な値引きキャンペーンを実施","新人営業の練習相手として活用"]', 1, '休眠顧客には過去の取引を分析し、相手にとって価値ある情報を提供することが効果的です。', 'E: 顧客管理 - 研修47', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (80, '顧客紹介を依頼する最適なタイミングは？', '["契約直後のテンションが高い時","顧客が成果を実感した時","契約更新の交渉時にお願いする","定例ミーティングの最後に依頼"]', 1, '紹介依頼は顧客が成果を実感し、満足度が高まったタイミングが最も効果的です。', 'E: 顧客管理 - 研修48', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (81, '顧客データベースで最低限管理すべき情報は？', '["氏名と連絡先のみで十分である","取引履歴・接触履歴・ニーズ情報など","競合他社の利用状況のみ","決裁権の有無だけ管理すれば良い"]', 1, '顧客DBには取引履歴、接触履歴、ニーズ、課題など、関係構築に必要な情報を管理します。', 'E: 顧客管理 - 研修41', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (82, 'RFM分析の3つの指標として正しいのは？', '["Revenue, Frequency, Market","Recency, Frequency, Monetary","Rate, Factor, Measure","Reach, Focus, Method"]', 1, 'RFMは最終購買日(Recency)、購買頻度(Frequency)、購買金額(Monetary)の3指標で顧客を分析します。', 'E: 顧客管理 - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (83, 'カスタマーサクセスの考え方で正しいのは？', '["顧客からの問い合わせに対応すること","顧客の成功を能動的に支援すること","顧客満足度を定期的に測定すること","顧客の要望を全て受け入れること"]', 1, 'カスタマーサクセスは受動的な対応ではなく、能動的に顧客の成功を支援する考え方です。', 'E: 顧客管理 - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (84, '顧客との定期ミーティングで重要なことは？', '["自社の新製品情報を必ず紹介する","顧客の状況変化や新たなニーズを確認","前回の議事録を一緒に読み合わせる","毎回同じアジェンダで効率化する"]', 1, '定期ミーティングでは顧客の状況変化や新たなニーズを確認し、提案機会を見つけます。', 'E: 顧客管理 - 研修43', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (85, '営業の時間管理で最も重要なことは？', '["できるだけ多くの顧客を訪問すること","重要度と緊急度で優先順位をつけること","上司の指示を最優先で対応すること","残業を減らして効率化すること"]', 1, '時間管理では重要度と緊急度のマトリクスで優先順位をつけ、重要なことに時間を使います。', 'F: セルフマネジメント - 研修50', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (86, '営業目標設定で「SMARTの法則」の「S」は？', '["Simple（シンプルな目標）","Specific（具体的な目標）","Strong（強い意志の目標）","Short（短期の目標）"]', 1, 'SMARTのSはSpecific（具体的）です。曖昧でない明確な目標を設定します。', 'F: セルフマネジメント - 研修51', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (87, '営業でPDCAサイクルを回す意義は？', '["上司への報告を効率化できるから","継続的な改善で成果を向上させるため","業務を標準化できるから","チーム内で情報共有できるから"]', 1, 'PDCAは計画→実行→評価→改善を繰り返し、継続的に成果を向上させるためのサイクルです。', 'F: セルフマネジメント - 研修52', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (88, '営業におけるモチベーション維持の方法は？', '["常に高い目標を設定し追い込む","小さな成功体験を積み重ねる","成績上位者と自分を常に比較する","報酬だけを目標にして頑張る"]', 1, 'モチベーション維持には小さな成功体験の積み重ねが効果的。達成感が次の行動につながります。', 'F: セルフマネジメント - 研修53', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (89, '営業日報を書く本来の目的は？', '["上司が営業活動を管理するため","自己の活動を振り返り改善するため","会社の記録として残すため","労働時間を証明するため"]', 1, '営業日報の本来の目的は、自己の活動を振り返り、改善点を見つけることです。', 'F: セルフマネジメント - 研修54', 'basic');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (90, 'スランプから抜け出すための効果的な方法は？', '["量をこなして確率で成果を出す","基本に立ち返り成功パターンを見直す","新しい手法を次々と試してみる","しばらく休んでリフレッシュする"]', 1, 'スランプ時は基本に立ち返り、過去の成功パターンを見直すことが効果的です。', 'F: セルフマネジメント - 研修55', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (91, '「パレートの法則（80:20の法則）」の営業での活用は？', '["上位20%の営業が80%の売上を上げる","上位20%の顧客に集中してアプローチ","時間の20%を勉強に使う","営業の80%は既存顧客対応に使う"]', 1, '売上の80%は上位20%の顧客からもたらされます。この顧客に集中することで効率が上がります。', 'F: セルフマネジメント - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (92, '営業の「ゾーン」に入る条件として正しいのは？', '["適度なプレッシャーと高いスキルの組合せ","完全にリラックスした状態であること","極度の緊張状態を維持すること","長時間の連続勤務による集中"]', 0, 'フロー状態（ゾーン）は、適度な挑戦とスキルが釣り合った時に生まれる最適な集中状態です。', 'F: セルフマネジメント - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (93, 'ストレスマネジメントで効果的な方法は？', '["ストレスを感じないように努力する","ストレスの原因を特定し対処法を考える","ストレスは気にしないことが一番","常にポジティブに考えるように努める"]', 1, 'ストレスは避けられません。原因を特定し、適切な対処法を考えることが重要です。', 'F: セルフマネジメント - 研修56', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (94, '営業スキル向上のための自己投資で効果的なのは？', '["営業本を年間100冊読むこと","学んだことを実践し振り返ること","高額なセミナーに参加すること","トップ営業の動画を毎日見ること"]', 1, '学びの定着には実践と振り返りが不可欠。インプットだけでなくアウトプットが重要です。', 'F: セルフマネジメント - 研修57', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (95, '「成長マインドセット」の特徴として正しいのは？', '["自分の能力は生まれつき決まっている","努力と学習で能力は伸ばせると信じる","失敗を避けて確実な方法を選ぶ","他人との競争で自分を高める"]', 1, '成長マインドセットは、努力と学習で能力は伸ばせるという信念。失敗も成長機会と捉えます。', 'F: セルフマネジメント - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (96, '「アイゼンハワーマトリクス」の第2領域とは？', '["緊急かつ重要なタスク","緊急ではないが重要なタスク","緊急だが重要ではないタスク","緊急でも重要でもないタスク"]', 1, '第2領域は「緊急ではないが重要」なタスク。ここに時間を使うことが成果につながります。', 'F: セルフマネジメント - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (97, '営業のルーティン化で得られる効果は？', '["毎日同じ行動で飽きが来ない","意思決定の負担を減らし集中できる","上司への報告が簡単になる","残業時間を削減できる"]', 1, 'ルーティン化により意思決定の負担が減り、重要なことに集中できるようになります。', 'F: セルフマネジメント - 研修58', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (98, '「レジリエンス」を高める方法として正しいのは？', '["失敗しないように慎重に行動する","失敗から学び回復する力を養う","常に成功イメージだけを持つ","ストレスを感じる環境を避ける"]', 1, 'レジリエンスは逆境から回復する力。失敗を恐れず、そこから学ぶ姿勢が重要です。', 'F: セルフマネジメント - 深掘り読み物', 'advanced');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (99, '長期的なキャリア形成で営業が意識すべきことは？', '["常に数字を追い求め続けること","専門性と人脈を計画的に築くこと","できるだけ早く管理職になること","一つの会社に長く勤めること"]', 1, '長期的なキャリア形成には、専門性と人脈を計画的に築くことが重要です。', 'F: セルフマネジメント - 研修59', 'intermediate');
INSERT INTO final_exam_questions (question_number, question, options, correct_answer, explanation, source, difficulty) VALUES (100, '営業として成長し続けるために最も重要なことは？', '["常に高い売上目標を達成し続けること","謙虚に学び続ける姿勢を持ち続けること","業界でトップの営業になること","後輩の育成に力を注ぐこと"]', 1, '環境変化が激しい中、謙虚に学び続ける姿勢が長期的な成長と成果につながります。', 'F: セルフマネジメント - 研修60', 'basic');
INSERT INTO category_deep_dive_contents (category_id, title, subtitle, body_html) VALUES ('C', '中古車流通の構造と現状', 'Symphony営業担当者のための業界深掘りテキスト', '<section class="border-b border-border bg-gradient-to-b from-amber-50 to-background py-12"><div class="mx-auto max-w-4xl px-4"><a class="mb-6 inline-flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground transition-colors" href="/category/C"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-arrow-left h-4 w-4"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg>業界知識：中古車ビジネスに戻る</a><div class="flex items-start gap-4"><div class="flex h-16 w-16 items-center justify-center rounded-xl bg-amber-500 text-white"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-book-open h-8 w-8"><path d="M12 7v14"></path><path d="M3 18a1 1 0 0 1-1-1V4a1 1 0 0 1 1-1h5a4 4 0 0 1 4 4 4 4 0 0 1 4-4h5a1 1 0 0 1 1 1v13a1 1 0 0 1-1 1h-6a3 3 0 0 0-3 3 3 3 0 0 0-3-3z"></path></svg></div><div><span data-slot="badge" class="inline-flex items-center justify-center rounded-md border px-2 py-0.5 text-xs font-medium w-fit whitespace-nowrap shrink-0 [&amp;&gt;svg]:size-3 gap-1 [&amp;&gt;svg]:pointer-events-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive transition-[color,box-shadow] overflow-hidden border-transparent bg-secondary text-secondary-foreground [a&amp;]:hover:bg-secondary/90 mb-2">深掘りテキスト</span><h1 class="text-3xl font-bold">中古車流通の構造と現状</h1><p class="mt-2 text-muted-foreground">Symphony営業担当者のための業界深掘りテキスト</p></div></div></div></section><section class="border-b border-border bg-secondary/30 py-8"><div class="mx-auto max-w-4xl px-4"><h2 class="mb-4 text-lg font-semibold">目次</h2><div class="grid gap-3 sm:grid-cols-2"><a href="#chapter1" class="flex items-center gap-3 rounded-lg border border-border bg-background p-3 hover:border-amber-500 transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-trending-up h-5 w-5 text-amber-500"><polyline points="22 7 13.5 15.5 8.5 10.5 2 17"></polyline><polyline points="16 7 22 7 22 13"></polyline></svg><span class="text-sm font-medium">第1章：中古車流通市場の全体像</span></a><a href="#chapter2" class="flex items-center gap-3 rounded-lg border border-border bg-background p-3 hover:border-amber-500 transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-truck h-5 w-5 text-amber-500"><path d="M14 18V6a2 2 0 0 0-2-2H4a2 2 0 0 0-2 2v11a1 1 0 0 0 1 1h2"></path><path d="M15 18H9"></path><path d="M19 18h2a1 1 0 0 0 1-1v-3.65a1 1 0 0 0-.22-.624l-3.48-4.35A1 1 0 0 0 17.52 8H14"></path><circle cx="17" cy="18" r="2"></circle><circle cx="7" cy="18" r="2"></circle></svg><span class="text-sm font-medium">第2章：仕入れ構造の詳細分析</span></a><a href="#chapter3" class="flex items-center gap-3 rounded-lg border border-border bg-background p-3 hover:border-amber-500 transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-shopping-cart h-5 w-5 text-amber-500"><circle cx="8" cy="21" r="1"></circle><circle cx="19" cy="21" r="1"></circle><path d="M2.05 2.05h2l2.66 12.42a2 2 0 0 0 2 1.58h9.78a2 2 0 0 0 1.95-1.57l1.65-7.43H5.12"></path></svg><span class="text-sm font-medium">第3章：在庫から販売までのプロセス</span></a><a href="#chapter4" class="flex items-center gap-3 rounded-lg border border-border bg-background p-3 hover:border-amber-500 transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-lightbulb h-5 w-5 text-amber-500"><path d="M15 14c.2-1 .7-1.7 1.5-2.5 1-.9 1.5-2.2 1.5-3.5A6 6 0 0 0 6 8c0 1 .2 2.2 1.5 3.5.7.7 1.3 1.5 1.5 2.5"></path><path d="M9 18h6"></path><path d="M10 22h4"></path></svg><span class="text-sm font-medium">第4章：流通における課題と変革</span></a></div></div></section><article class="py-12"><div class="mx-auto max-w-4xl px-4"><section id="chapter1" class="mb-16 scroll-mt-8"><div class="mb-8 flex items-center gap-3"><div class="flex h-10 w-10 items-center justify-center rounded-lg bg-amber-500 text-white"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-trending-up h-5 w-5"><polyline points="22 7 13.5 15.5 8.5 10.5 2 17"></polyline><polyline points="16 7 22 7 22 13"></polyline></svg></div><h2 class="text-2xl font-bold">第1章：中古車流通市場の全体像</h2></div><div class="space-y-8"><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">1.1 市場規模と経済的位置づけ</h3><h4 class="mb-3 font-semibold text-amber-600">国内中古車市場の規模</h4><p class="mb-4 leading-relaxed text-muted-foreground">日本の中古車市場は、新車市場を凌駕する巨大なマーケットです。2023年の統計によれば、中古車登録台数は約695万台に達し、新車販売台数（約478万台）の約1.45倍の規模を誇ります。金額ベースでは、中古車小売市場は約4兆円規模と推計され、関連サービス（整備、保険、ローン等）を含めると約7兆円の経済圏を形成しています。</p><div class="mb-6 overflow-x-auto"><table class="w-full text-sm"><caption class="mb-2 text-left font-medium">中古車・新車販売台数の推移（万台）</caption><thead><tr class="border-b border-border bg-secondary/50"><th class="px-4 py-2 text-left">年度</th><th class="px-4 py-2 text-right">中古車</th><th class="px-4 py-2 text-right">新車</th><th class="px-4 py-2 text-right">比率</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-4 py-2">2019年</td><td class="px-4 py-2 text-right">693</td><td class="px-4 py-2 text-right">520</td><td class="px-4 py-2 text-right">1.33</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2">2020年</td><td class="px-4 py-2 text-right">649</td><td class="px-4 py-2 text-right">460</td><td class="px-4 py-2 text-right">1.41</td></tr><tr class="border-b border-border"><td class="px-4 py-2">2021年</td><td class="px-4 py-2 text-right">671</td><td class="px-4 py-2 text-right">445</td><td class="px-4 py-2 text-right">1.51</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2">2022年</td><td class="px-4 py-2 text-right">686</td><td class="px-4 py-2 text-right">456</td><td class="px-4 py-2 text-right">1.50</td></tr><tr class="border-b border-border"><td class="px-4 py-2 font-medium">2023年</td><td class="px-4 py-2 text-right font-medium">695</td><td class="px-4 py-2 text-right font-medium">478</td><td class="px-4 py-2 text-right font-medium">1.45</td></tr></tbody></table><p class="mt-2 text-xs text-muted-foreground">※中古車は登録車+軽自動車の合計　※出典：日本自動車販売協会連合会、全国軽自動車協会連合会</p></div><div class="rounded-lg bg-amber-50 p-4"><p class="text-sm leading-relaxed"><strong>注目ポイント：</strong>コロナ禍（2020-2021年）において新車の供給が半導体不足等により制約を受けた際、中古車への代替需要が顕在化し、中古車価格の高騰という現象が発生しました。これは中古車市場が単なる「新車の受け皿」ではなく、独立した市場として機能していることを示しています。</p></div></div><div class="rounded-lg border border-border p-6"><h4 class="mb-4 font-semibold text-amber-600">中古車流通の経済的意義</h4><div class="space-y-4"><div class="flex gap-4"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-100 text-amber-600 font-bold text-sm">1</div><div><h5 class="font-medium">資産の有効活用</h5><p class="mt-1 text-sm text-muted-foreground">自動車は住宅に次ぐ高額耐久消費財です。中古車流通が存在することで、車両の経済的寿命が延長され、資源の有効活用が図られます。日本では平均車齢（初度登録からの経過年数）が13.84年（2023年）に達しています。</p></div></div><div class="flex gap-4"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-100 text-amber-600 font-bold text-sm">2</div><div><h5 class="font-medium">消費者の選択肢拡大</h5><p class="mt-1 text-sm text-muted-foreground">中古車市場の存在により、消費者は予算や用途に応じて幅広い選択肢から車両を選ぶことができます。新車では手が届かない上位車種や、すでに生産終了したモデルを入手することも可能です。</p></div></div><div class="flex gap-4"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-100 text-amber-600 font-bold text-sm">3</div><div><h5 class="font-medium">地域経済への貢献</h5><p class="mt-1 text-sm text-muted-foreground">全国に約5万店舗存在する中古車販売店は、その多くが地域密着型の中小企業です。これらの事業者は地域の雇用を支え、整備業、保険業、金融業など関連産業への波及効果も大きいです。</p></div></div></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">1.2 流通構造の全体像</h3><h4 class="mb-3 font-semibold text-amber-600">サプライチェーンとしての中古車流通</h4><p class="mb-4 leading-relaxed text-muted-foreground">中古車流通は、製造業における原材料調達から製品販売までのサプライチェーンに類似した構造を持ちます。ただし、「原材料」に相当する中古車は、新車ディーラー、一般消費者、レンタカー会社、リース会社など多様なソースから発生する点が特徴的です。</p><div class="mb-6 rounded-lg bg-secondary/50 p-4"><h5 class="mb-3 font-medium">流通経路別のボリューム</h5><div class="space-y-3"><div class="flex items-center gap-3"><div class="h-4 w-4 rounded bg-amber-500"></div><span class="font-medium">オートオークション経由（約70%）</span></div><p class="ml-7 text-sm text-muted-foreground">全国に約130会場が存在し、年間約700万台が取引されます。価格形成の透明性、品質の標準化、取引の効率性、信用リスクの軽減が特徴です。</p><div class="flex items-center gap-3"><div class="h-4 w-4 rounded bg-amber-400"></div><span class="font-medium">下取り・買取による直接仕入れ（約20%）</span></div><p class="ml-7 text-sm text-muted-foreground">オークション手数料が不要で、現車確認が確実。顧客関係の構築にも繋がりますが、希望車種が入庫する保証がないのが課題です。</p><div class="flex items-center gap-3"><div class="h-4 w-4 rounded bg-amber-300"></div><span class="font-medium">業販プラットフォーム経由（約10%）</span></div><p class="ml-7 text-sm text-muted-foreground">販売店間の直接取引を仲介するB2Bプラットフォームであり、近年成長が著しい分野です。シンフォニーワンプラ、オートサーバー、オークネットなどが代表的なサービスです。</p></div></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">1.3 主要プレイヤーの分析</h3><h4 class="mb-3 font-semibold text-amber-600">オートオークション会社</h4><div class="mb-6 overflow-x-auto"><table class="w-full text-sm"><thead><tr class="border-b border-border bg-secondary/50"><th class="px-4 py-2 text-left">会社名</th><th class="px-4 py-2 text-right">会場数</th><th class="px-4 py-2 text-right">年間取引台数</th><th class="px-4 py-2 text-left">特徴</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-4 py-2 font-medium">USS</td><td class="px-4 py-2 text-right">19会場</td><td class="px-4 py-2 text-right">約250万台</td><td class="px-4 py-2 text-muted-foreground">業界最大手、東証プライム上場</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">JU（中販連系）</td><td class="px-4 py-2 text-right">約50会場</td><td class="px-4 py-2 text-right">約150万台</td><td class="px-4 py-2 text-muted-foreground">業界団体系、地域密着</td></tr><tr class="border-b border-border"><td class="px-4 py-2 font-medium">TAA（トヨタ系）</td><td class="px-4 py-2 text-right">8会場</td><td class="px-4 py-2 text-right">約80万台</td><td class="px-4 py-2 text-muted-foreground">トヨタ系ディーラー出品中心</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">HAA神戸</td><td class="px-4 py-2 text-right">2会場</td><td class="px-4 py-2 text-right">約40万台</td><td class="px-4 py-2 text-muted-foreground">関西圏に強み</td></tr></tbody></table></div><h4 class="mb-3 font-semibold text-amber-600">中古車販売店の分類</h4><div class="grid gap-4 sm:grid-cols-3"><div class="rounded-lg bg-secondary/50 p-4"><h5 class="font-medium">大規模チェーン</h5><p class="text-xs text-muted-foreground">在庫100台以上</p><p class="mt-2 text-sm">店舗数では全体の1%未満だが、販売台数では約15%を占めます。</p></div><div class="rounded-lg bg-secondary/50 p-4"><h5 class="font-medium">中規模店</h5><p class="text-xs text-muted-foreground">在庫30〜100台</p><p class="mt-2 text-sm">全体の約5%。整備工場を併設し、ワンストップサービスを提供。</p></div><div class="rounded-lg bg-secondary/50 p-4"><h5 class="font-medium">小規模店</h5><p class="text-xs text-muted-foreground">在庫30台未満</p><p class="mt-2 text-sm">全国の約95%を占め、家族経営や個人事業主が中心。</p></div></div></div></div></section><section id="chapter2" class="mb-16 scroll-mt-8"><div class="mb-8 flex items-center gap-3"><div class="flex h-10 w-10 items-center justify-center rounded-lg bg-amber-500 text-white"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-truck h-5 w-5"><path d="M14 18V6a2 2 0 0 0-2-2H4a2 2 0 0 0-2 2v11a1 1 0 0 0 1 1h2"></path><path d="M15 18H9"></path><path d="M19 18h2a1 1 0 0 0 1-1v-3.65a1 1 0 0 0-.22-.624l-3.48-4.35A1 1 0 0 0 17.52 8H14"></path><circle cx="17" cy="18" r="2"></circle><circle cx="7" cy="18" r="2"></circle></svg></div><h2 class="text-2xl font-bold">第2章：仕入れ構造の詳細分析</h2></div><div class="space-y-8"><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">2.1 オートオークションの機能と役割</h3><h4 class="mb-3 font-semibold text-amber-600">市場としてのオークション</h4><div class="grid gap-4 sm:grid-cols-2"><div class="rounded-lg border border-amber-200 bg-amber-50 p-4"><h5 class="font-medium">価格発見機能</h5><p class="mt-1 text-sm text-muted-foreground">競争入札により、需要と供給が均衡する価格が発見されます。この価格は「相場」として業界全体で参照されます。</p></div><div class="rounded-lg border border-amber-200 bg-amber-50 p-4"><h5 class="font-medium">流動性供給機能</h5><p class="mt-1 text-sm text-muted-foreground">売りたい時に売れる、買いたい時に買える「流動性」を提供します。</p></div><div class="rounded-lg border border-amber-200 bg-amber-50 p-4"><h5 class="font-medium">品質保証機能</h5><p class="mt-1 text-sm text-muted-foreground">検査員による評価点付けにより、品質に関する情報の非対称性を軽減します。</p></div><div class="rounded-lg border border-amber-200 bg-amber-50 p-4"><h5 class="font-medium">決済保証機能</h5><p class="mt-1 text-sm text-muted-foreground">オークション会社が売り手と買い手の間に入り、代金決済を保証します。</p></div></div></div><div class="rounded-lg border border-border p-6"><h4 class="mb-4 font-semibold text-amber-600">評価点制度の詳細</h4><div class="overflow-x-auto"><table class="w-full text-sm"><thead><tr class="border-b border-border bg-secondary/50"><th class="px-4 py-2 text-left">評価点</th><th class="px-4 py-2 text-left">状態</th><th class="px-4 py-2 text-left">特徴</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-4 py-2 font-medium">S点</td><td class="px-4 py-2">新車に準ずる</td><td class="px-4 py-2 text-muted-foreground">走行距離1万km未満、内外装に目立つ傷なし</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">6点</td><td class="px-4 py-2">非常に良い</td><td class="px-4 py-2 text-muted-foreground">走行距離3万km未満、小売でそのまま販売可能</td></tr><tr class="border-b border-border"><td class="px-4 py-2 font-medium">5点</td><td class="px-4 py-2">状態が良い</td><td class="px-4 py-2 text-muted-foreground">走行距離5万km未満、標準的な中古車</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">4.5点</td><td class="px-4 py-2">やや良い</td><td class="px-4 py-2 text-muted-foreground">走行距離10万km未満、補修すれば小売可能</td></tr><tr class="border-b border-border"><td class="px-4 py-2 font-medium">4点</td><td class="px-4 py-2">標準的</td><td class="px-4 py-2 text-muted-foreground">走行距離制限なし、補修費用を考慮した仕入れが必要</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">3.5点</td><td class="px-4 py-2">やや劣る</td><td class="px-4 py-2 text-muted-foreground">傷・へこみが多い、業販・輸出向け</td></tr><tr class="border-b border-border"><td class="px-4 py-2 font-medium">R点</td><td class="px-4 py-2">修復歴あり</td><td class="px-4 py-2 text-muted-foreground">骨格部分の修復履歴あり</td></tr></tbody></table></div><div class="mt-4 rounded-lg bg-amber-50 p-4"><p class="text-sm"><strong>価格への影響：</strong>一般的に、評価点が0.5ポイント上がると、同一車種・同一年式で5〜10%程度価格が上昇する傾向があります。</p></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">2.2 下取り・買取の構造</h3><div class="mb-4 grid gap-4 sm:grid-cols-2"><div class="rounded-lg border border-border p-4"><h5 class="font-medium text-amber-600">下取り</h5><p class="mt-2 text-sm text-muted-foreground">車両購入時に現有車を販売店に売却。購入車両とのパッケージで交渉されることが多い。</p></div><div class="rounded-lg border border-border p-4"><h5 class="font-medium text-amber-600">買取</h5><p class="mt-2 text-sm text-muted-foreground">車両売却のみを目的とした取引。車両の市場価値のみで価格が決定される。</p></div></div><h4 class="mb-3 font-semibold">査定価格の算出方法</h4><div class="rounded-lg bg-secondary/50 p-4 font-mono text-sm"><p>査定価格 = 基本価値 − 減価額 − 利益マージン − リスクバッファ</p><p class="mt-2 text-muted-foreground">※利益マージン：5〜15%　※リスクバッファ：3〜5%</p></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">2.3 業販プラットフォームの台頭</h3><p class="mb-4 text-muted-foreground">「業販（ぎょうはん）」とは、業者間販売の略称であり、中古車販売店同士が直接取引を行う形態を指します。2000年代以降のインターネット普及に伴い、オンラインプラットフォームによる業販が急速に発展しました。</p><h4 class="mb-3 font-semibold text-amber-600">シンフォニーワンプラの競争優位性</h4><div class="space-y-3"><div class="flex gap-3"><div class="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">1</div><div><h5 class="font-medium">販売管理システムとの垂直統合</h5><p class="text-sm text-muted-foreground">Symphony販売管理を利用する販売店は、在庫データを自動でワンプラに連携。出品作業が数分で完了します。</p></div></div><div class="flex gap-3"><div class="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">2</div><div><h5 class="font-medium">陸送ネットワークとの連携</h5><p class="text-sm text-muted-foreground">提携陸送会社とのシステム連携により、落札後の陸送手配がスムーズ。料金の透明性も高いです。</p></div></div><div class="flex gap-3"><div class="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">3</div><div><h5 class="font-medium">品質保証制度</h5><p class="text-sm text-muted-foreground">出品車両に対する検査基準を設け、トラブルを防止する仕組みを構築しています。</p></div></div></div></div></div></section><section id="chapter3" class="mb-16 scroll-mt-8"><div class="mb-8 flex items-center gap-3"><div class="flex h-10 w-10 items-center justify-center rounded-lg bg-amber-500 text-white"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-shopping-cart h-5 w-5"><circle cx="8" cy="21" r="1"></circle><circle cx="19" cy="21" r="1"></circle><path d="M2.05 2.05h2l2.66 12.42a2 2 0 0 0 2 1.58h9.78a2 2 0 0 0 1.95-1.57l1.65-7.43H5.12"></path></svg></div><h2 class="text-2xl font-bold">第3章：在庫から販売までのプロセス</h2></div><div class="space-y-8"><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">3.1 商品化工程の詳細</h3><p class="mb-4 text-muted-foreground">「商品化」とは、仕入れた車両を販売可能な状態に仕上げる一連の作業を指します。この工程の品質が、販売価格と成約率に直結します。</p><div class="mb-6 space-y-2"><div class="flex items-center gap-3 rounded-lg bg-secondary/50 p-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">1</div><div><span class="font-medium">入庫検査（30分）</span><span class="ml-2 text-sm text-muted-foreground">外装・内装の状態確認、機関チェック</span></div></div><div class="flex items-center gap-3 rounded-lg bg-secondary/50 p-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">2</div><div><span class="font-medium">整備計画（15分）</span><span class="ml-2 text-sm text-muted-foreground">必要な整備項目の洗い出し、部品発注</span></div></div><div class="flex items-center gap-3 rounded-lg bg-secondary/50 p-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">3</div><div><span class="font-medium">整備（2〜8時間）</span><span class="ml-2 text-sm text-muted-foreground">法定点検項目、消耗品交換、不具合修理</span></div></div><div class="flex items-center gap-3 rounded-lg bg-secondary/50 p-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">4</div><div><span class="font-medium">板金塗装（必要時）</span><span class="ml-2 text-sm text-muted-foreground">傷の補修、へこみの修理</span></div></div><div class="flex items-center gap-3 rounded-lg bg-secondary/50 p-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">5</div><div><span class="font-medium">クリーニング（1〜2時間）</span><span class="ml-2 text-sm text-muted-foreground">外装洗車・コーティング、内装清掃・消臭</span></div></div><div class="flex items-center gap-3 rounded-lg bg-secondary/50 p-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">6</div><div><span class="font-medium">写真撮影・掲載（1時間）</span><span class="ml-2 text-sm text-muted-foreground">外装・内装の撮影、車両情報の入力</span></div></div></div><h4 class="mb-3 font-semibold text-amber-600">商品化コストの構造</h4><div class="overflow-x-auto"><table class="w-full text-sm"><thead><tr class="border-b border-border bg-secondary/50"><th class="px-4 py-2 text-left">コスト項目</th><th class="px-4 py-2 text-right">50万円以下</th><th class="px-4 py-2 text-right">50〜100万円</th><th class="px-4 py-2 text-right">100〜200万円</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-4 py-2">点検整備費</td><td class="px-4 py-2 text-right">15,000円</td><td class="px-4 py-2 text-right">25,000円</td><td class="px-4 py-2 text-right">35,000円</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2">消耗品交換</td><td class="px-4 py-2 text-right">10,000円</td><td class="px-4 py-2 text-right">15,000円</td><td class="px-4 py-2 text-right">20,000円</td></tr><tr class="border-b border-border"><td class="px-4 py-2">板金・塗装（平均）</td><td class="px-4 py-2 text-right">20,000円</td><td class="px-4 py-2 text-right">25,000円</td><td class="px-4 py-2 text-right">30,000円</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2">クリーニング</td><td class="px-4 py-2 text-right">5,000円</td><td class="px-4 py-2 text-right">8,000円</td><td class="px-4 py-2 text-right">10,000円</td></tr><tr class="border-b border-border font-medium"><td class="px-4 py-2">合計（平均）</td><td class="px-4 py-2 text-right">53,000円</td><td class="px-4 py-2 text-right">76,000円</td><td class="px-4 py-2 text-right">100,000円</td></tr><tr class="bg-amber-50"><td class="px-4 py-2 font-medium">対車両価格比</td><td class="px-4 py-2 text-right font-medium text-amber-600">10.6%</td><td class="px-4 py-2 text-right font-medium text-amber-600">7.6%</td><td class="px-4 py-2 text-right font-medium text-amber-600">5.0%</td></tr></tbody></table></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">3.2 価格設定のメカニズム</h3><div class="mb-4 rounded-lg bg-secondary/50 p-4 font-mono text-sm"><p class="font-medium">販売価格 = 仕入れコスト + 商品化コスト + 目標粗利 + 価格調整</p><ul class="mt-2 space-y-1 text-muted-foreground"><li>・仕入れコスト：車両価格 + 手数料 + 陸送費 + 消費税</li><li>・商品化コスト：整備費 + 板金費 + クリーニング費 + 撮影費</li><li>・目標粗利：仕入れコストの10〜25%（店舗方針による）</li></ul></div><h4 class="mb-3 font-semibold text-amber-600">在庫日数と価格調整</h4><p class="mb-3 text-sm text-muted-foreground">在庫として滞留する期間が長くなると、相場下落リスク、資金固定リスク、陳腐化リスクが増大します。そのため、在庫日数に応じた価格調整ルールを設けている販売店が多いです。</p><div class="overflow-x-auto"><table class="w-full text-sm"><thead><tr class="border-b border-border bg-secondary/50"><th class="px-4 py-2 text-left">在庫日数</th><th class="px-4 py-2 text-left">価格調整</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-4 py-2">0〜30日</td><td class="px-4 py-2">販売価格維持</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2">31〜60日</td><td class="px-4 py-2">5%値下げ</td></tr><tr class="border-b border-border"><td class="px-4 py-2">61〜90日</td><td class="px-4 py-2">10%値下げ</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2">91〜120日</td><td class="px-4 py-2">15%値下げ or 業販出品</td></tr><tr class="border-b border-border"><td class="px-4 py-2">121日以上</td><td class="px-4 py-2">業販 or オークション再出品</td></tr></tbody></table></div></div></div></section><section id="chapter4" class="mb-16 scroll-mt-8"><div class="mb-8 flex items-center gap-3"><div class="flex h-10 w-10 items-center justify-center rounded-lg bg-amber-500 text-white"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-lightbulb h-5 w-5"><path d="M15 14c.2-1 .7-1.7 1.5-2.5 1-.9 1.5-2.2 1.5-3.5A6 6 0 0 0 6 8c0 1 .2 2.2 1.5 3.5.7.7 1.3 1.5 1.5 2.5"></path><path d="M9 18h6"></path><path d="M10 22h4"></path></svg></div><h2 class="text-2xl font-bold">第4章：流通における課題と変革</h2></div><div class="space-y-8"><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">4.1 構造的課題</h3><h4 class="mb-3 font-semibold text-amber-600">情報の非対称性</h4><div class="mb-4 space-y-3"><div class="rounded-lg border-l-4 border-amber-500 bg-amber-50 p-4"><h5 class="font-medium">品質に関する非対称性</h5><p class="mt-1 text-sm text-muted-foreground">売り手（販売店）は車両の状態を熟知しているが、買い手（消費者）は限定的な情報しか持たない。消費者の不信感やレモン問題を引き起こします。</p></div><div class="rounded-lg border-l-4 border-amber-500 bg-amber-50 p-4"><h5 class="font-medium">価格に関する非対称性</h5><p class="mt-1 text-sm text-muted-foreground">オークション相場や業者間価格は、一般消費者にはアクセスしにくい。提示された価格が適正かどうかの判断が困難です。</p></div></div><h4 class="mb-3 font-semibold text-amber-600">人手不足と生産性</h4><div class="grid gap-3 sm:grid-cols-3"><div class="rounded-lg bg-secondary/50 p-3"><h5 class="font-medium text-sm">営業職</h5><p class="mt-1 text-xs text-muted-foreground">若年層の応募減少、「営業＝ノルマ」のネガティブイメージ</p></div><div class="rounded-lg bg-secondary/50 p-3"><h5 class="font-medium text-sm">整備士</h5><p class="mt-1 text-xs text-muted-foreground">資格保有者の減少、給与水準の低さ（平均年収約380万円）</p></div><div class="rounded-lg bg-secondary/50 p-3"><h5 class="font-medium text-sm">事務職</h5><p class="mt-1 text-xs text-muted-foreground">登録業務の煩雑さ、ITリテラシーの必要性向上</p></div></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">4.2 テクノロジーによる変革</h3><h4 class="mb-3 font-semibold text-amber-600">DX（デジタルトランスフォーメーション）の進展</h4><div class="grid gap-4 sm:grid-cols-2"><div class="rounded-lg border border-border p-4"><h5 class="font-medium">仕入れのデジタル化</h5><ul class="mt-2 space-y-1 text-sm text-muted-foreground"><li>・オンラインオークション（衛星入札、TV入札）</li><li>・業販プラットフォームの普及</li><li>・AI相場予測ツールの登場</li></ul></div><div class="rounded-lg border border-border p-4"><h5 class="font-medium">在庫管理のシステム化</h5><ul class="mt-2 space-y-1 text-sm text-muted-foreground"><li>・クラウド型在庫管理システム</li><li>・在庫回転率のリアルタイム可視化</li><li>・長期在庫アラート機能</li></ul></div><div class="rounded-lg border border-border p-4"><h5 class="font-medium">販売のオンライン化</h5><ul class="mt-2 space-y-1 text-sm text-muted-foreground"><li>・オンライン商談（Zoom等）</li><li>・VR/360度画像による遠隔確認</li><li>・非対面契約の普及</li></ul></div><div class="rounded-lg border border-border p-4"><h5 class="font-medium">顧客管理のCRM化</h5><ul class="mt-2 space-y-1 text-sm text-muted-foreground"><li>・顧客データベースの構築</li><li>・車検・点検リマインドの自動化</li><li>・購買履歴に基づくアプローチ</li></ul></div></div></div><div class="rounded-lg border border-amber-200 bg-amber-50 p-6"><h4 class="mb-4 font-semibold text-amber-600">Symphonyシリーズが提供する価値</h4><p class="mb-4 text-sm text-muted-foreground">ファブリカホールディングスのSymphonyシリーズは、上記のDX領域をカバーする統合ソリューションです。</p><div class="space-y-3"><div class="rounded-lg bg-background p-4"><h5 class="font-medium">Symphony販売管理</h5><p class="mt-1 text-sm text-muted-foreground">在庫管理、顧客管理、帳票出力、分析機能を一元管理</p></div><div class="rounded-lg bg-background p-4"><h5 class="font-medium">Symphony整備請求</h5><p class="mt-1 text-sm text-muted-foreground">整備見積、請求管理、車検リマインド、整備履歴管理</p></div><div class="rounded-lg bg-background p-4"><h5 class="font-medium">シンフォニーワンプラ</h5><p class="mt-1 text-sm text-muted-foreground">業販仕入れ・販売、陸送手配、Symphony連携による自動データ連携</p></div></div></div><div class="rounded-lg border border-border p-6"><h3 class="mb-4 text-xl font-semibold">4.3 今後の展望</h3><h4 class="mb-3 font-semibold text-amber-600">市場構造の変化予測</h4><div class="mb-6 space-y-3"><div class="flex gap-3"><div class="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">1</div><div><h5 class="font-medium">オンライン取引の拡大</h5><p class="text-sm text-muted-foreground">コロナ禍を契機に加速したオンライン化は、今後も継続。遠方の顧客への販売、業者間取引のオンライン化が進む。</p></div></div><div class="flex gap-3"><div class="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">2</div><div><h5 class="font-medium">業界再編の加速</h5><p class="text-sm text-muted-foreground">大手チェーンの拡大と中小販売店の淘汰が進む可能性。一方で、専門性や地域密着を強みとする中小店舗が生き残る道も。</p></div></div><div class="flex gap-3"><div class="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white text-xs font-bold">3</div><div><h5 class="font-medium">EVシフトへの対応</h5><p class="text-sm text-muted-foreground">EV（電気自動車）の普及に伴い、中古EV市場も拡大。バッテリー評価、整備体制など、新たな対応が求められる。</p></div></div></div><h4 class="mb-3 font-semibold text-amber-600">販売店の生き残り戦略</h4><div class="overflow-x-auto"><table class="w-full text-sm"><thead><tr class="border-b border-border bg-secondary/50"><th class="px-4 py-2 text-left">戦略領域</th><th class="px-4 py-2 text-left">具体的施策</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-4 py-2 font-medium">デジタル化</td><td class="px-4 py-2 text-muted-foreground">業務システムの導入（Symphony等）、オンライン集客の強化、データに基づく経営判断</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">顧客関係強化</td><td class="px-4 py-2 text-muted-foreground">整備・車検を通じた継続接点、CRMによる顧客管理、紹介・リピートの促進</td></tr><tr class="border-b border-border"><td class="px-4 py-2 font-medium">収益構造改善</td><td class="px-4 py-2 text-muted-foreground">整備収益の拡大、保険・ローン手数料の獲得、付帯サービスの提案</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-4 py-2 font-medium">専門性強化</td><td class="px-4 py-2 text-muted-foreground">特定車種への特化、地域No.1の確立、EV整備など新技術への対応</td></tr></tbody></table></div></div></div></section><section class="mb-16"><div class="rounded-lg border-2 border-amber-500 bg-gradient-to-br from-amber-50 to-background p-8"><h2 class="mb-4 text-2xl font-bold">おわりに：営業担当者への示唆</h2><p class="mb-4 leading-relaxed text-muted-foreground">本テキストで解説した中古車流通の構造と現状を理解することは、Symphony営業担当者にとって以下の意義があります。</p><div class="space-y-4"><div class="flex gap-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white font-bold">1</div><div><h4 class="font-medium">顧客との対話の質向上</h4><p class="mt-1 text-sm text-muted-foreground">業界の構造を理解することで、顧客（中古車販売店）の課題や悩みを深く理解できます。「この営業は業界をわかっている」と信頼を得ることが、商談の第一歩となります。</p></div></div><div class="flex gap-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white font-bold">2</div><div><h4 class="font-medium">課題に基づく提案</h4><p class="mt-1 text-sm text-muted-foreground">流通の各段階における課題を理解することで、Symphonyの機能が「どの課題を解決するか」を具体的に説明できます。</p></div></div><div class="flex gap-3"><div class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-amber-500 text-white font-bold">3</div><div><h4 class="font-medium">長期的なパートナーシップ</h4><p class="mt-1 text-sm text-muted-foreground">単なるシステム販売ではなく、販売店の経営課題を共に解決するパートナーとしての姿勢が、長期的な関係構築につながります。</p></div></div></div><div class="mt-6 rounded-lg bg-amber-100 p-4"><p class="text-center text-sm font-medium">中古車流通は、一見すると複雑に見えますが、「仕入れ→在庫→販売」という基本的な流れを理解すれば、全体像が見えてきます。<br/>本テキストが、その理解の一助となれば幸いです。</p></div></div></section><section class="mb-8"><div class="mb-8 flex items-center gap-3"><div class="flex h-10 w-10 items-center justify-center rounded-lg bg-secondary text-foreground"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-chart-column h-5 w-5"><path d="M3 3v16a2 2 0 0 0 2 2h16"></path><path d="M18 17V9"></path><path d="M13 17V5"></path><path d="M8 17v-3"></path></svg></div><h2 class="text-2xl font-bold">付録：参考データ・統計</h2></div><div class="grid gap-6 lg:grid-cols-2"><div class="rounded-lg border border-border p-4"><h4 class="mb-3 font-semibold">中古車登録台数の推移</h4><table class="w-full text-xs"><thead><tr class="border-b border-border"><th class="px-2 py-1 text-left">年度</th><th class="px-2 py-1 text-right">登録車</th><th class="px-2 py-1 text-right">軽自動車</th><th class="px-2 py-1 text-right">合計</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-2 py-1">2021年</td><td class="px-2 py-1 text-right">356万台</td><td class="px-2 py-1 text-right">315万台</td><td class="px-2 py-1 text-right">671万台</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-2 py-1">2022年</td><td class="px-2 py-1 text-right">362万台</td><td class="px-2 py-1 text-right">324万台</td><td class="px-2 py-1 text-right">686万台</td></tr><tr><td class="px-2 py-1 font-medium">2023年</td><td class="px-2 py-1 text-right font-medium">369万台</td><td class="px-2 py-1 text-right font-medium">326万台</td><td class="px-2 py-1 text-right font-medium">695万台</td></tr></tbody></table></div><div class="rounded-lg border border-border p-4"><h4 class="mb-3 font-semibold">中古車販売店の店舗数推移</h4><table class="w-full text-xs"><thead><tr class="border-b border-border"><th class="px-2 py-1 text-left">年度</th><th class="px-2 py-1 text-right">店舗数</th><th class="px-2 py-1 text-right">前年比</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-2 py-1">2021年</td><td class="px-2 py-1 text-right">49,123店</td><td class="px-2 py-1 text-right text-red-500">-1.1%</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-2 py-1">2022年</td><td class="px-2 py-1 text-right">48,567店</td><td class="px-2 py-1 text-right text-red-500">-1.1%</td></tr><tr><td class="px-2 py-1 font-medium">2023年</td><td class="px-2 py-1 text-right font-medium">48,012店</td><td class="px-2 py-1 text-right font-medium text-red-500">-1.1%</td></tr></tbody></table></div><div class="rounded-lg border border-border p-4"><h4 class="mb-3 font-semibold">オークション取引台数の推移</h4><table class="w-full text-xs"><thead><tr class="border-b border-border"><th class="px-2 py-1 text-left">年度</th><th class="px-2 py-1 text-right">取引台数</th><th class="px-2 py-1 text-right">落札率</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-2 py-1">2021年</td><td class="px-2 py-1 text-right">695万台</td><td class="px-2 py-1 text-right">69.1%</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-2 py-1">2022年</td><td class="px-2 py-1 text-right">710万台</td><td class="px-2 py-1 text-right">66.5%</td></tr><tr><td class="px-2 py-1 font-medium">2023年</td><td class="px-2 py-1 text-right font-medium">705万台</td><td class="px-2 py-1 text-right font-medium">65.2%</td></tr></tbody></table></div><div class="rounded-lg border border-border p-4"><h4 class="mb-3 font-semibold">中古車輸出台数の推移</h4><table class="w-full text-xs"><thead><tr class="border-b border-border"><th class="px-2 py-1 text-left">年度</th><th class="px-2 py-1 text-right">輸出台数</th><th class="px-2 py-1 text-left">主要仕向地</th></tr></thead><tbody><tr class="border-b border-border"><td class="px-2 py-1">2021年</td><td class="px-2 py-1 text-right">118万台</td><td class="px-2 py-1">ロシア、UAE、NZ</td></tr><tr class="border-b border-border bg-secondary/30"><td class="px-2 py-1">2022年</td><td class="px-2 py-1 text-right">138万台</td><td class="px-2 py-1">ロシア、UAE、ケニア</td></tr><tr><td class="px-2 py-1 font-medium">2023年</td><td class="px-2 py-1 text-right font-medium">132万台</td><td class="px-2 py-1 font-medium">UAE、ケニア、タンザニア</td></tr></tbody></table></div></div></section><div class="flex justify-center"><a class="inline-flex items-center gap-2 rounded-lg bg-amber-500 px-6 py-3 font-medium text-white hover:bg-amber-600 transition-colors" href="/category/C"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-arrow-left h-4 w-4"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg>業界知識：中古車ビジネスに戻る</a></div></div></article>');
